sql:
SELECT program_id AS program_name
FROM programs
WHERE category_id = 1 AND level = '1' AND program_head = 1;

external_knowledge:
- Pathways: Represent the unique program IDs;
- Gates: Symbolize the various branch names that represent specific areas of study;
- Towers of knowledge: Metaphors for academic levels such as undergraduate and postgraduate studies;

sql:
SELECT program_id, curriculum_version
FROM programs
WHERE curriculum_version = (SELECT MAX(curriculum_version) FROM programs);

external_knowledge:
- "approved" refers to programs that have successfully passed through an internal review process;
- "branches" symbolize the various directions or departments supported by each program;
- "duration" reflects the time each program has been active or thriving;
- "user_id" identifies the individuals responsible for managing or nurturing these programs.

sql:
SELECT p.degree, u.user_name 
FROM programs p
INNER JOIN users u ON p.program_head = u.user_id;
